; 
; A Positive correlation indicates that as the weather improves, the number of trips increases; 
; A Negative correlation indicates that as the weather improves, the number of trips decreases; 
; A Neutral correlation indicates that there is no significant relationship between the weather and the number of trips.

sql:
SELECT MAX(average_speed) 
FROM transportation_modes
WHERE fuel_type = 'diesel';
